INSERT INTO kreo_products (set_number, name, franchise, sub_line, year, piece_count, kreons_count, kreons_included, description, price_retail, product_type, image_url, image_path, pdf_url, pdf_path, wiki_url, wiki_image_url, discovered_at, updated_at) VALUES ('A2235', 'Mech Venom Strike set', 'transformers', 'Beast Hunters', 2013, 49, 1, 'Windcharger', 'It’s a Beast Hunters showdown with the Mech Venom Strike set! The 49 pieces in this awesome 2-in-1 set let you build a Transformers figure as a terrifying beast or a vehicle. Whichever one you build, send your Windcharger Kreon figure into battle with him! Build your TRANSFORMERS adventures, then tear them down to build new ones! Works with major construction brands.', 3.99, 'building_set', NULL, 'transformers/a2235.jpg', NULL, 'pdfs/A2235_instructions_scan.pdf', 'https://kreo.fandom.com/wiki/Mech%20Venom%20Strike%20(Kre-O)', 'https://static.wikia.nocookie.net/kreo/images/4/45/3EFA344350569047F5B55F29021DA770.jpg/revision/latest?cb=20130313021955', '2026-03-01 06:59:29.903254'::timestamp, '2026-03-01 10:29:48.616546'::timestamp) ON CONFLICT (set_number) DO UPDATE SET name = EXCLUDED.name, franchise = EXCLUDED.franchise, sub_line = EXCLUDED.sub_line, year = EXCLUDED.year, piece_count = EXCLUDED.piece_count, kreons_count = EXCLUDED.kreons_count, kreons_included = EXCLUDED.kreons_included, description = EXCLUDED.description, price_retail = EXCLUDED.price_retail, product_type = EXCLUDED.product_type, image_url = EXCLUDED.image_url, image_path = EXCLUDED.image_path, pdf_url = EXCLUDED.pdf_url, pdf_path = EXCLUDED.pdf_path, wiki_url = EXCLUDED.wiki_url, wiki_image_url = EXCLUDED.wiki_image_url, updated_at = EXCLUDED.updated_at;
INSERT INTO kreo_products (set_number, name, franchise, sub_line, year, piece_count, kreons_count, kreons_included, description, price_retail, product_type, image_url, image_path, pdf_url, pdf_path, wiki_url, wiki_image_url, discovered_at, updated_at) VALUES ('A2201', 'Ripclaw Strike Set', 'transformers', 'Beast Hunters', 2013, 199, 1, 'Predacons:
*Ripclaw
Humans:
*[[Daniel Witwicky (A2201)', 'Create it with Kre-O building sets! Build the Predacon cyber-dragon Ripclaw in beast mode or robot mode with the Kre-O Transformers Beast Hunters Ripclaw Strike building set. With Kre-O building sets, you can create all kinds of adventures. Build with attitude using the colorful bricks, cool Kreon figures and accessory pieces!

Build with Attitude! The battle between the Autobots and the Decepticons continues as Predacon beasts join the Decepticons in the fight to conquer the world. With the Kre-O Transformers Beast Hunters Ripclaw Strike building set, you can recreate the story of Ripclaw as he comes to Earth to search for the all-powerful Energon. Build Ripclaw in beast mode or robot mode! The set comes with 2 Kreon figures and includes a unique action brick that makes the wings really flap.
*Release Date: 2013
*MSRP: $16.99', 16.99, 'building_set', NULL, 'transformers/a2201.jpg', NULL, NULL, 'https://kreo.fandom.com/wiki/Ripclaw%20Strike%20(Kre-O)', 'https://static.wikia.nocookie.net/kreo/images/7/70/3EFB626550569047F5BACD88A74091FD.jpg/revision/latest?cb=20130314031439', '2026-03-01 06:59:32.647204'::timestamp, '2026-03-01 09:27:44.801291'::timestamp) ON CONFLICT (set_number) DO UPDATE SET name = EXCLUDED.name, franchise = EXCLUDED.franchise, sub_line = EXCLUDED.sub_line, year = EXCLUDED.year, piece_count = EXCLUDED.piece_count, kreons_count = EXCLUDED.kreons_count, kreons_included = EXCLUDED.kreons_included, description = EXCLUDED.description, price_retail = EXCLUDED.price_retail, product_type = EXCLUDED.product_type, image_url = EXCLUDED.image_url, image_path = EXCLUDED.image_path, pdf_url = EXCLUDED.pdf_url, pdf_path = EXCLUDED.pdf_path, wiki_url = EXCLUDED.wiki_url, wiki_image_url = EXCLUDED.wiki_image_url, updated_at = EXCLUDED.updated_at;
INSERT INTO kreo_products (set_number, name, franchise, sub_line, year, piece_count, kreons_count, kreons_included, description, price_retail, product_type, image_url, image_path, pdf_url, pdf_path, wiki_url, wiki_image_url, discovered_at, updated_at) VALUES ('A6739', 'Battle Fortress', 'dungeons-dragons', 'Original', 2014, 297, 1, '''''unknown at this time''''', 'Also promoted as the Fortress Defense set, the Battle Fortress is a Kre-O Dungeons & Dragons construction set representing an orcish siege on a human fortification. It includes six kreons (two humans, and four orcs), as well as parts to build a fortress wall including a working drawbridge and collapsible wall, and a wheeled orcish catapult that can launch the included red balls.', 24.99, 'building_set', NULL, 'dungeons-dragons/a6739.jpg', NULL, NULL, 'https://kreo.fandom.com/wiki/Battle%20Fortress', 'https://static.wikia.nocookie.net/kreo/images/1/1d/Battle_fortress_01.jpg/revision/latest/scale-to-width-down/800?cb=20140105180948', '2026-03-01 06:59:35.108524'::timestamp, '2026-03-01 09:36:28.003075'::timestamp) ON CONFLICT (set_number) DO UPDATE SET name = EXCLUDED.name, franchise = EXCLUDED.franchise, sub_line = EXCLUDED.sub_line, year = EXCLUDED.year, piece_count = EXCLUDED.piece_count, kreons_count = EXCLUDED.kreons_count, kreons_included = EXCLUDED.kreons_included, description = EXCLUDED.description, price_retail = EXCLUDED.price_retail, product_type = EXCLUDED.product_type, image_url = EXCLUDED.image_url, image_path = EXCLUDED.image_path, pdf_url = EXCLUDED.pdf_url, pdf_path = EXCLUDED.pdf_path, wiki_url = EXCLUDED.wiki_url, wiki_image_url = EXCLUDED.wiki_image_url, updated_at = EXCLUDED.updated_at;
INSERT INTO kreo_products (set_number, name, franchise, sub_line, year, piece_count, kreons_count, kreons_included, description, price_retail, product_type, image_url, image_path, pdf_url, pdf_path, wiki_url, wiki_image_url, discovered_at, updated_at) VALUES ('A6742', 'Fortress Tower', 'dungeons-dragons', 'Original', 2014, 200, 1, '''''unknown at this time''''', 'The Fortress Tower is a Kre-O Dungeons & Dragons construction set representing an orcish siege on a human fortification.  It includes four kreons (two humans and two orcs), as well as parts to build a fortress wall including a tower that tilts as if collapsing when struck, and a stationary orcish catapult that can launch the included red balls.', 19.99, 'building_set', NULL, 'dungeons-dragons/a6742.jpg', NULL, NULL, 'https://kreo.fandom.com/wiki/Fortress%20Tower', 'https://static.wikia.nocookie.net/kreo/images/8/8e/Fortress_tower_01.jpg/revision/latest/scale-to-width-down/800?cb=20140105180739', '2026-03-01 06:59:38.071936'::timestamp, '2026-03-01 09:36:28.003075'::timestamp) ON CONFLICT (set_number) DO UPDATE SET name = EXCLUDED.name, franchise = EXCLUDED.franchise, sub_line = EXCLUDED.sub_line, year = EXCLUDED.year, piece_count = EXCLUDED.piece_count, kreons_count = EXCLUDED.kreons_count, kreons_included = EXCLUDED.kreons_included, description = EXCLUDED.description, price_retail = EXCLUDED.price_retail, product_type = EXCLUDED.product_type, image_url = EXCLUDED.image_url, image_path = EXCLUDED.image_path, pdf_url = EXCLUDED.pdf_url, pdf_path = EXCLUDED.pdf_path, wiki_url = EXCLUDED.wiki_url, wiki_image_url = EXCLUDED.wiki_image_url, updated_at = EXCLUDED.updated_at;
