INSERT INTO kreo_products (set_number, name, franchise, sub_line, year, piece_count, kreons_count, kreons_included, description, price_retail, product_type, image_url, image_path, pdf_url, pdf_path, wiki_url, wiki_image_url, discovered_at, updated_at) VALUES ('98814', 'Stealth Bumblebee Set', 'transformers', 'Quest for Energon', 2012, 257, 4, 'Bumblebee, Biker, Security Guard (2), Bulldog', 'Part of the "Quest for Energon" series, this set contains one piece of the Dark Energon Weapon, The Quest Blaster !', 29.99, 'building_set', NULL, 'transformers/98814.jpg', NULL, 'pdfs/98814_instructions_scan.pdf', 'https://kreo.fandom.com/wiki/Stealth%20Bumblebee', 'https://static.wikia.nocookie.net/kreo/images/0/08/Stealth-Bumblebee-Box_1350914621.jpg/revision/latest/scale-to-width-down/800?cb=20130219021319', '2026-03-01 06:59:49.617927'::timestamp, '2026-03-01 10:29:34.898711'::timestamp) ON CONFLICT (set_number) DO UPDATE SET name = EXCLUDED.name, franchise = EXCLUDED.franchise, sub_line = EXCLUDED.sub_line, year = EXCLUDED.year, piece_count = EXCLUDED.piece_count, kreons_count = EXCLUDED.kreons_count, kreons_included = EXCLUDED.kreons_included, description = EXCLUDED.description, price_retail = EXCLUDED.price_retail, product_type = EXCLUDED.product_type, image_url = EXCLUDED.image_url, image_path = EXCLUDED.image_path, pdf_url = EXCLUDED.pdf_url, pdf_path = EXCLUDED.pdf_path, wiki_url = EXCLUDED.wiki_url, wiki_image_url = EXCLUDED.wiki_image_url, updated_at = EXCLUDED.updated_at;
INSERT INTO kreo_products (set_number, name, franchise, sub_line, year, piece_count, kreons_count, kreons_included, description, price_retail, product_type, image_url, image_path, pdf_url, pdf_path, wiki_url, wiki_image_url, discovered_at, updated_at) VALUES ('A2202', 'Battle Net Bumblebee Set', 'transformers', 'Beast Hunters', 2013, 178, 1, 'Autobots:
*[[Bumblebee (A2202)', 'Build your own Transformers adventures with this awesome KRE-O Construction set! With the 178 bricks and other construction pieces in this set, you can build a Bumblebee robot and send it into the fray with his battle net in hand! Your Bumblebee and Soldier Kreon figures are ready to fight at his side. When the battle is on the line and Bumblebee has a need for speed, rebuild him as a vehicle and put your Kreon figures inside for a wild ride! Keep building and rebuilding for epic Transformers action! 
*Release Date: 2013
*MSRP: $16.99', 16.99, 'building_set', NULL, 'transformers/a2202.jpg', NULL, NULL, 'https://kreo.fandom.com/wiki/Battle%20Net%20Bumblebee', 'https://static.wikia.nocookie.net/kreo/images/d/dd/3EFBB45E50569047F5725C2CA1A8E05D.jpg/revision/latest?cb=20130219021725', '2026-03-01 06:59:51.481771'::timestamp, '2026-03-01 09:35:22.581256'::timestamp) ON CONFLICT (set_number) DO UPDATE SET name = EXCLUDED.name, franchise = EXCLUDED.franchise, sub_line = EXCLUDED.sub_line, year = EXCLUDED.year, piece_count = EXCLUDED.piece_count, kreons_count = EXCLUDED.kreons_count, kreons_included = EXCLUDED.kreons_included, description = EXCLUDED.description, price_retail = EXCLUDED.price_retail, product_type = EXCLUDED.product_type, image_url = EXCLUDED.image_url, image_path = EXCLUDED.image_path, pdf_url = EXCLUDED.pdf_url, pdf_path = EXCLUDED.pdf_path, wiki_url = EXCLUDED.wiki_url, wiki_image_url = EXCLUDED.wiki_image_url, updated_at = EXCLUDED.updated_at;
INSERT INTO kreo_products (set_number, name, franchise, sub_line, year, piece_count, kreons_count, kreons_included, description, price_retail, product_type, image_url, image_path, pdf_url, pdf_path, wiki_url, wiki_image_url, discovered_at, updated_at) VALUES ('A6949', 'Dinobot Charge Set', 'transformers', 'Age of Extinction', 2014, 66, 1, 'Autobots:
*Autobot Drift
Decepticons:
*Vehicon', 'Build your own dino-on-robot Transformers adventures with the Dinobot Charge set! You can use the 66 pieces in this set to build a raging dino, and put your Autobot Drift Kreon on his back for a mighty charge. Will your Vehicon Kreon be able to fight off his 2-sword attack with his blaster? Or will he take on the dino with his magnetic head charge? It''s all up to you!', 9.99, 'building_set', NULL, 'transformers/a6949.jpg', NULL, NULL, 'https://kreo.fandom.com/wiki/Dinobot%20Charge', 'https://static.wikia.nocookie.net/kreo/images/9/9c/PTRU1-18179504_alternate1_dt.jpg/revision/latest?cb=20140611024928', '2026-03-01 06:59:55.256446'::timestamp, '2026-03-01 09:30:51.421311'::timestamp) ON CONFLICT (set_number) DO UPDATE SET name = EXCLUDED.name, franchise = EXCLUDED.franchise, sub_line = EXCLUDED.sub_line, year = EXCLUDED.year, piece_count = EXCLUDED.piece_count, kreons_count = EXCLUDED.kreons_count, kreons_included = EXCLUDED.kreons_included, description = EXCLUDED.description, price_retail = EXCLUDED.price_retail, product_type = EXCLUDED.product_type, image_url = EXCLUDED.image_url, image_path = EXCLUDED.image_path, pdf_url = EXCLUDED.pdf_url, pdf_path = EXCLUDED.pdf_path, wiki_url = EXCLUDED.wiki_url, wiki_image_url = EXCLUDED.wiki_image_url, updated_at = EXCLUDED.updated_at;
INSERT INTO kreo_products (set_number, name, franchise, sub_line, year, piece_count, kreons_count, kreons_included, description, price_retail, product_type, image_url, image_path, pdf_url, pdf_path, wiki_url, wiki_image_url, discovered_at, updated_at) VALUES ('A8600', 'Grimlock Unleashed Set', 'transformers', 'Age of Extinction', 2014, 333, 1, 'Autobots:
*[[Optimus Prime (A8600)', 'Check out the new KRE-O TRANSFORMERS GRIMLOCK UNLEASHED building set! This G1-inspired build of Grimlock is 333 pieces and includes 5 KREON figures: Optimus Prime, Bumblebee, Galvatron, Lockdown and G1 Grimlock with crown. Build the largest version of T-Rex Grimlock ever made!
*Release Date: May 2014', NULL, 'building_set', NULL, 'transformers/a8600.jpg', NULL, NULL, 'https://kreo.fandom.com/wiki/Grimlock%20Unleashed', 'https://static.wikia.nocookie.net/kreo/images/d/d7/Tfaoekre-o-grim2-1.jpg/revision/latest?cb=20140611025637', '2026-03-01 06:59:56.797994'::timestamp, '2026-03-01 06:59:56.797994'::timestamp) ON CONFLICT (set_number) DO UPDATE SET name = EXCLUDED.name, franchise = EXCLUDED.franchise, sub_line = EXCLUDED.sub_line, year = EXCLUDED.year, piece_count = EXCLUDED.piece_count, kreons_count = EXCLUDED.kreons_count, kreons_included = EXCLUDED.kreons_included, description = EXCLUDED.description, price_retail = EXCLUDED.price_retail, product_type = EXCLUDED.product_type, image_url = EXCLUDED.image_url, image_path = EXCLUDED.image_path, pdf_url = EXCLUDED.pdf_url, pdf_path = EXCLUDED.pdf_path, wiki_url = EXCLUDED.wiki_url, wiki_image_url = EXCLUDED.wiki_image_url, updated_at = EXCLUDED.updated_at;
