INSERT INTO kreo_products (set_number, name, franchise, sub_line, year, piece_count, kreons_count, kreons_included, description, price_retail, product_type, image_url, image_path, pdf_url, pdf_path, wiki_url, wiki_image_url, discovered_at, updated_at) VALUES ('A7837', 'Custom Kreon Autobot Ratchet Set', 'transformers', 'Custom Kreons', 2014, 29, 1, 'Ratchet', 'Build 16 different versions of your Autobot Ratchet KREON figure with the 29 pieces in this custom KRE-O construction set! The set includes pieces for blasters and other weapons, and your Autobot Ratchet KREON figure also has a stand for all his battle gear. Which way will you build him? What will he carry into battle? It''s all up to you!
