*Release Date: May 2014
*MSRP: $3.99', 3.99, 'custom_kreon', NULL, 'transformers/a7839.jpg', NULL, NULL, 'https://kreo.fandom.com/wiki/Drift%20(A7839)', 'https://static.wikia.nocookie.net/kreo/images/a/a2/PTRU1-18359130_alternate1_enh-z6.jpg/revision/latest/scale-to-width-down/800?cb=20140909155114', '2026-03-01 07:00:04.74025'::timestamp, '2026-03-01 09:26:33.282705'::timestamp) ON CONFLICT (set_number) DO UPDATE SET name = EXCLUDED.name, franchise = EXCLUDED.franchise, sub_line = EXCLUDED.sub_line, year = EXCLUDED.year, piece_count = EXCLUDED.piece_count, kreons_count = EXCLUDED.kreons_count, kreons_included = EXCLUDED.kreons_included, description = EXCLUDED.description, price_retail = EXCLUDED.price_retail, product_type = EXCLUDED.product_type, image_url = EXCLUDED.image_url, image_path = EXCLUDED.image_path, pdf_url = EXCLUDED.pdf_url, pdf_path = EXCLUDED.pdf_path, wiki_url = EXCLUDED.wiki_url, wiki_image_url = EXCLUDED.wiki_image_url, updated_at = EXCLUDED.updated_at;
