INSERT INTO kreo_products (set_number, name, franchise, sub_line, year, piece_count, kreons_count, kreons_included, description, price_retail, product_type, image_url, image_path, pdf_url, pdf_path, wiki_url, wiki_image_url, discovered_at, updated_at) VALUES ('A6087', 'Custom Kreon Bumblebee Set', 'transformers', 'Custom Kreons', 2013, 40, 1, 'Bumblebee', 'Build 16 different versions of your Bumblebee Kreon with the 40 pieces in this Custom Kreon set! The set includes pieces for swords, blasters and other weapons, and your Bumblebee Kreon also has several helmets for each attack on the Decepticons (other Custom Kreon sets sold separately). Which way will you build him? What will he carry into battle? It''s all up to you!

