INSERT INTO kreo_products (set_number, name, franchise, sub_line, year, piece_count, kreons_count, kreons_included, description, price_retail, product_type, image_url, image_path, pdf_url, pdf_path, wiki_url, wiki_image_url, discovered_at, updated_at) VALUES ('B0951', 'Optimus Prime Beast Blaster Set', 'transformers', 'Robots in Disguise', 2015, 247, 1, 'Autobots:
*[[Optimus Prime (B0951)', 'Build your own TRANSFORMERS ROBOTS IN DISGUISE adventures with this awesome KRE-O TRANSFORMERS construction set! You can use the KRE-O bricks to build the Optimus Prime truck with secret reveal missile launcher and dual cannons that flip down for battle with the Decepticon hovercraft. Comes with Optimus Prime Kreon and Decepticon Fracture, Airazor and Divebomb Kreons and one capture pod.
*Release Date: Spring 2015', 29.99, 'building_set', NULL, 'transformers/b0951.jpg', NULL, NULL, 'https://kreo.fandom.com/wiki/Optimus%20Prime%20Beast%20Blaster%20(2015)', 'https://static.wikia.nocookie.net/kreo/images/1/17/Kre-o-op-beast-blaster-box.jpg/revision/latest?cb=20150325122704', '2026-03-01 07:00:11.295428'::timestamp, '2026-03-01 09:29:29.343949'::timestamp) ON CONFLICT (set_number) DO UPDATE SET name = EXCLUDED.name, franchise = EXCLUDED.franchise, sub_line = EXCLUDED.sub_line, year = EXCLUDED.year, piece_count = EXCLUDED.piece_count, kreons_count = EXCLUDED.kreons_count, kreons_included = EXCLUDED.kreons_included, description = EXCLUDED.description, price_retail = EXCLUDED.price_retail, product_type = EXCLUDED.product_type, image_url = EXCLUDED.image_url, image_path = EXCLUDED.image_path, pdf_url = EXCLUDED.pdf_url, pdf_path = EXCLUDED.pdf_path, wiki_url = EXCLUDED.wiki_url, wiki_image_url = EXCLUDED.wiki_image_url, updated_at = EXCLUDED.updated_at;
INSERT INTO kreo_products (set_number, name, franchise, sub_line, year, piece_count, kreons_count, kreons_included, description, price_retail, product_type, image_url, image_path, pdf_url, pdf_path, wiki_url, wiki_image_url, discovered_at, updated_at) VALUES ('B0949', 'Bumblebee Disc Demolishor Set', 'transformers', 'Robots in Disguise', 2015, 186, 1, '[[Bumblebee (B0949)', 'Bumblebee is the new Autobot team leader, and he''s rolling out with plenty of firepower on his mission to catch the rampaging Decepticons. Be part of the chase with this KRE-O battle vehicle building set. The Bumblebee Disc Demolisher features a Bumblebee racecar build complete with a blasting disc ''launcher. The building set comes with a Bumblebee Kreon figure and two Decepticon Kreon figures, Bisk and Clampdown. Imagine you''re racing after the escaped Decepticons on a mission to save Earth. Once they''re captured, place the Decepticon figures inside the stasis pod to put them back on lockdown. The stasis pod automatically snaps shut when you put a Kreon figure inside! 
*Release Date: Spring 2015', NULL, 'building_set', NULL, 'transformers/b0949.jpg', NULL, NULL, 'https://kreo.fandom.com/wiki/Bumblebee%20Disc%20Demolishor%20(2015)', 'https://static.wikia.nocookie.net/kreo/images/b/be/Kre-o-bb-disc-demolishor-box.jpg/revision/latest?cb=20150325120645', '2026-03-01 07:00:13.436933'::timestamp, '2026-03-01 07:00:13.436933'::timestamp) ON CONFLICT (set_number) DO UPDATE SET name = EXCLUDED.name, franchise = EXCLUDED.franchise, sub_line = EXCLUDED.sub_line, year = EXCLUDED.year, piece_count = EXCLUDED.piece_count, kreons_count = EXCLUDED.kreons_count, kreons_included = EXCLUDED.kreons_included, description = EXCLUDED.description, price_retail = EXCLUDED.price_retail, product_type = EXCLUDED.product_type, image_url = EXCLUDED.image_url, image_path = EXCLUDED.image_path, pdf_url = EXCLUDED.pdf_url, pdf_path = EXCLUDED.pdf_path, wiki_url = EXCLUDED.wiki_url, wiki_image_url = EXCLUDED.wiki_image_url, updated_at = EXCLUDED.updated_at;
