INSERT INTO kreo_products (set_number, name, franchise, sub_line, year, piece_count, kreons_count, kreons_included, description, price_retail, product_type, image_url, image_path, pdf_url, pdf_path, wiki_url, wiki_image_url, discovered_at, updated_at) VALUES ('KR-15', 'Hound', 'transformers', 'Original', 2011, NULL, NULL, NULL, 'Hound (KR-15) is a cancelled Kreon of the character Hound from Transformers. 



Amid the launch of KRE-O, a display case at multiple conventions unveiled all of the Transformers Kreons set to release in 2011. This display case contained a prototype of the Hound Kreon, with a roughly glued on decal of his chest printing. When the line officially launched, none of the listed sets contained this Hound Kreon. Seemingly cancelled.', NULL, 'building_set', NULL, 'transformers/kr-15.jpg', NULL, NULL, 'https://kreo.fandom.com/wiki/Hound%20(KR-15)', 'https://static.wikia.nocookie.net/kreo/images/c/c5/HoundCancelledKR15.jpg/revision/latest/scale-to-width-down/800?cb=20240620231625', '2026-03-01 07:02:39.173456'::timestamp, '2026-03-01 09:35:22.840416'::timestamp) ON CONFLICT (set_number) DO UPDATE SET name = EXCLUDED.name, franchise = EXCLUDED.franchise, sub_line = EXCLUDED.sub_line, year = EXCLUDED.year, piece_count = EXCLUDED.piece_count, kreons_count = EXCLUDED.kreons_count, kreons_included = EXCLUDED.kreons_included, description = EXCLUDED.description, price_retail = EXCLUDED.price_retail, product_type = EXCLUDED.product_type, image_url = EXCLUDED.image_url, image_path = EXCLUDED.image_path, pdf_url = EXCLUDED.pdf_url, pdf_path = EXCLUDED.pdf_path, wiki_url = EXCLUDED.wiki_url, wiki_image_url = EXCLUDED.wiki_image_url, updated_at = EXCLUDED.updated_at;
INSERT INTO kreo_products (set_number, name, franchise, sub_line, year, piece_count, kreons_count, kreons_included, description, price_retail, product_type, image_url, image_path, pdf_url, pdf_path, wiki_url, wiki_image_url, discovered_at, updated_at) VALUES ('A687700', 'Army Builder Pack', 'dungeons-dragons', 'Original', 2014, NULL, NULL, NULL, 'Build your Dungeons &amp; Dragons KREON army with the Army Builder Packs! Each pack contains 1 KREON figure with weapons for awesome KRE-O battles. You can add an Orc Wardrummer, Spearman or 10 other KREONS! Your adventures will get more incredible with every KREON Army Builder Pack you get! Includes 1 KREON and 1 KREON card. Build your Dungeons &amp; Dragons army with the Army Builder Pack. Each KREON comes armed with weapon. Collect all 12 (each sold separately). Ages 6 to 12 years. KRE-O and all related characters are trademarks of Hasbro. Hasbro and all related terms are trademarks of Hasbro.', 2.49, 'building_set', NULL, NULL, NULL, NULL, 'https://kreo.fandom.com/wiki/Army_Builder', NULL, '2026-03-01 07:02:54.023125'::timestamp, '2026-03-01 09:36:28.003075'::timestamp) ON CONFLICT (set_number) DO UPDATE SET name = EXCLUDED.name, franchise = EXCLUDED.franchise, sub_line = EXCLUDED.sub_line, year = EXCLUDED.year, piece_count = EXCLUDED.piece_count, kreons_count = EXCLUDED.kreons_count, kreons_included = EXCLUDED.kreons_included, description = EXCLUDED.description, price_retail = EXCLUDED.price_retail, product_type = EXCLUDED.product_type, image_url = EXCLUDED.image_url, image_path = EXCLUDED.image_path, pdf_url = EXCLUDED.pdf_url, pdf_path = EXCLUDED.pdf_path, wiki_url = EXCLUDED.wiki_url, wiki_image_url = EXCLUDED.wiki_image_url, updated_at = EXCLUDED.updated_at;
