INSERT INTO kreo_products (set_number, name, franchise, sub_line, year, piece_count, kreons_count, kreons_included, description, price_retail, product_type, image_url, image_path, pdf_url, pdf_path, wiki_url, wiki_image_url, discovered_at, updated_at) VALUES ('KR7629', 'Matrix Optimus Prime', 'transformers', 'Micro-Changers', 2011, NULL, 1, 'Matrix Optimus Prime', 'Allegiance: Autobots. Matrix Optimus Prime is a redeco of the regular Optimus Prime Kreon has an open chest showing the Matrix of Leadership within. He comes with a G1 inspired gun and a black brick display stand.

Originally intended to be exclusive to BotCon 2011, this figure appears to have been produced in such quantities that it became available in other venues as well. It was handed out at San Diego Comic-Con 2011, offered as a free giveaway with any order that included Transformers toys on Hasbro Toy Shop, as a free gift on the cover of the Awesome Autobots Activity Book, and came as a free gift attached to issue #240 of the UK children''s comic, Doctor Who Adventures. Included with: ''''''[[Optimus Prime (30689)]]'''''' (factory error) <br>''''''Awesome Autobots Activity Book'''''' (Freebie)', NULL, 'kreon', NULL, 'kreons/kr7629.jpg', NULL, NULL, 'https://kreo.fandom.com/wiki/Matrix%20Optimus%20Prime', 'https://static.wikia.nocookie.net/kreo/images/0/0c/Kre-O-Matrix-Optimus-Prime.jpg/revision/latest?cb=20170207063007', '2026-03-01 07:52:50.273969'::timestamp, '2026-03-01 09:35:22.757667'::timestamp) ON CONFLICT (set_number) DO UPDATE SET name = EXCLUDED.name, franchise = EXCLUDED.franchise, sub_line = EXCLUDED.sub_line, year = EXCLUDED.year, piece_count = EXCLUDED.piece_count, kreons_count = EXCLUDED.kreons_count, kreons_included = EXCLUDED.kreons_included, description = EXCLUDED.description, price_retail = EXCLUDED.price_retail, product_type = EXCLUDED.product_type, image_url = EXCLUDED.image_url, image_path = EXCLUDED.image_path, pdf_url = EXCLUDED.pdf_url, pdf_path = EXCLUDED.pdf_path, wiki_url = EXCLUDED.wiki_url, wiki_image_url = EXCLUDED.wiki_image_url, updated_at = EXCLUDED.updated_at;
