INSERT INTO kreo_products (set_number, name, franchise, sub_line, year, piece_count, kreons_count, kreons_included, description, price_retail, product_type, image_url, image_path, pdf_url, pdf_path, wiki_url, wiki_image_url, discovered_at, updated_at) VALUES ('KR2370', 'Vortex', 'transformers', 'Micro-Changers Combiners', 2012, NULL, 1, 'Vortex', 'Allegiance: Decepticons. Vortex is a Decepticon Kreon released as part of the Rotor Rage Building Set, as well as in a different color scheme and some additional parts in wave 1 of the Kreon Micro Changer Combiners series as part of a set of 4 Combaticon kreons that combine to form Decepticon Bruticus. He uses the same helmet as Soundwave, one single Starscream arm blaster, and a vest piece that fits a helicopter rotor to allow it to spin freely. The version that came with the Rotor Rage set included an extra Dark Energon-colored transparent purple torso piece, while the Micro-Changer version had two arm blasters instead of one, as well as a piece to form his tail rotor in vehicle mode.

In the Transformers Webcomic, Vortex speaks with a distinctive verbal tic, ending every sentence with an "-ex" derived from his own name. Such a quirk is not unusual in Japanese media, where it is known as キャラ語尾 (kyara-gobi), meaning a "chara"(cter) word/suffix. A comparable character trait in English might be if he constantly Included with: [[Rotor Rage]], 
[[Decepticon Bruticus (A2225)', NULL, 'kreon', NULL, 'kreons/kr2370.jpg', NULL, NULL, 'https://kreo.fandom.com/wiki/Vortex', 'https://static.wikia.nocookie.net/kreo/images/7/77/077F4C355056900B10FE6AED05062D0B.jpg/revision/latest/scale-to-width-down/800?cb=20131217215008', '2026-03-01 07:54:25.822717'::timestamp, '2026-03-01 07:54:25.822717'::timestamp) ON CONFLICT (set_number) DO UPDATE SET name = EXCLUDED.name, franchise = EXCLUDED.franchise, sub_line = EXCLUDED.sub_line, year = EXCLUDED.year, piece_count = EXCLUDED.piece_count, kreons_count = EXCLUDED.kreons_count, kreons_included = EXCLUDED.kreons_included, description = EXCLUDED.description, price_retail = EXCLUDED.price_retail, product_type = EXCLUDED.product_type, image_url = EXCLUDED.image_url, image_path = EXCLUDED.image_path, pdf_url = EXCLUDED.pdf_url, pdf_path = EXCLUDED.pdf_path, wiki_url = EXCLUDED.wiki_url, wiki_image_url = EXCLUDED.wiki_image_url, updated_at = EXCLUDED.updated_at;
