Klingon kreons are found in the Transporter Trouble and Bird of Prey sets, as well as the Toys "R" Us exclusive Space Ship Face Off set. Included with: [[Star_Trek_Kreons', NULL, 'kreon', NULL, 'kreons/kr3071108.jpg', NULL, 'pdfs/KR3071108_instructions_scan.pdf', 'https://kreo.fandom.com/wiki/Klingon', 'https://static.wikia.nocookie.net/kreo/images/0/0f/Blind-Bag_Klingon.jpg/revision/latest?cb=20140104190611', '2026-03-01 07:54:32.920715'::timestamp, '2026-03-01 10:30:53.180489'::timestamp) ON CONFLICT (set_number) DO UPDATE SET name = EXCLUDED.name, franchise = EXCLUDED.franchise, sub_line = EXCLUDED.sub_line, year = EXCLUDED.year, piece_count = EXCLUDED.piece_count, kreons_count = EXCLUDED.kreons_count, kreons_included = EXCLUDED.kreons_included, description = EXCLUDED.description, price_retail = EXCLUDED.price_retail, product_type = EXCLUDED.product_type, image_url = EXCLUDED.image_url, image_path = EXCLUDED.image_path, pdf_url = EXCLUDED.pdf_url, pdf_path = EXCLUDED.pdf_path, wiki_url = EXCLUDED.wiki_url, wiki_image_url = EXCLUDED.wiki_image_url, updated_at = EXCLUDED.updated_at;
