INSERT INTO kreo_products (set_number, name, franchise, sub_line, year, piece_count, kreons_count, kreons_included, description, price_retail, product_type, image_url, image_path, pdf_url, pdf_path, wiki_url, wiki_image_url, discovered_at, updated_at) VALUES ('KR4666', 'Drizzt', 'dungeons-dragons', 'Kreon Warriors', 2014, 22, 1, 'Drizzt', 'Allegiance: Companions of the Hall. Drizzt is a Kreon Warrior representing the character Drizzt Do''Urden, a drow (dark elf) who rebelled against the evil nature of his culture to become a famous adventuring hero. Drizzt''s published adventures in the fantasy world of the Forgotten Realms campaign setting are among the most popular of all Dungeons and Dragons media, consistently winding up on the New York Times Best Seller List.

thumb|"Where in the [[w:c:forgottenrealms:Nine_Hells|Nine Hells did you ever find the notion that I would fight fair?"]] Included with: [[Kreon Warriors (D&D)]] 
Drizzt (A7710000)', 3.99, 'kreon', NULL, 'kreons/kr4666.jpg', NULL, NULL, 'https://kreo.fandom.com/wiki/Drizzt', 'https://static.wikia.nocookie.net/kreo/images/2/2c/Drizzt2.jpg/revision/latest/scale-to-width-down/800?cb=20140105194935', '2026-03-01 07:54:39.672997'::timestamp, '2026-03-01 09:25:24.010613'::timestamp) ON CONFLICT (set_number) DO UPDATE SET name = EXCLUDED.name, franchise = EXCLUDED.franchise, sub_line = EXCLUDED.sub_line, year = EXCLUDED.year, piece_count = EXCLUDED.piece_count, kreons_count = EXCLUDED.kreons_count, kreons_included = EXCLUDED.kreons_included, description = EXCLUDED.description, price_retail = EXCLUDED.price_retail, product_type = EXCLUDED.product_type, image_url = EXCLUDED.image_url, image_path = EXCLUDED.image_path, pdf_url = EXCLUDED.pdf_url, pdf_path = EXCLUDED.pdf_path, wiki_url = EXCLUDED.wiki_url, wiki_image_url = EXCLUDED.wiki_image_url, updated_at = EXCLUDED.updated_at;
INSERT INTO kreo_products (set_number, name, franchise, sub_line, year, piece_count, kreons_count, kreons_included, description, price_retail, product_type, image_url, image_path, pdf_url, pdf_path, wiki_url, wiki_image_url, discovered_at, updated_at) VALUES ('KR4667', 'Wulfgar', 'dungeons-dragons', 'Kreon Warriors', 2014, 26, 1, 'Wulfgar', 'Allegiance: Companions of the Hall. Wulfgar is a Kreon Warrior representing the character of the same name from the fantasy world of the Forgotten Realms campaign setting for Dungeons and Dragons. An adventuring companion of Drizzt, Wulfgar is especially notable for his enchanted war-hammer Aegis-Fang, a creation of his adopted father, the dwarf Bruenor Battlehammer. Included with: [[Kreon Warriors (D&D)]] 
Wulfgar (A7711000)', 19.99, 'kreon', NULL, 'kreons/kr4667.jpg', NULL, NULL, 'https://kreo.fandom.com/wiki/Wulfgar', 'https://static.wikia.nocookie.net/kreo/images/6/6d/Wulfgar02.jpg/revision/latest/scale-to-width-down/800?cb=20140105194027', '2026-03-01 07:54:42.097236'::timestamp, '2026-03-01 09:25:35.941138'::timestamp) ON CONFLICT (set_number) DO UPDATE SET name = EXCLUDED.name, franchise = EXCLUDED.franchise, sub_line = EXCLUDED.sub_line, year = EXCLUDED.year, piece_count = EXCLUDED.piece_count, kreons_count = EXCLUDED.kreons_count, kreons_included = EXCLUDED.kreons_included, description = EXCLUDED.description, price_retail = EXCLUDED.price_retail, product_type = EXCLUDED.product_type, image_url = EXCLUDED.image_url, image_path = EXCLUDED.image_path, pdf_url = EXCLUDED.pdf_url, pdf_path = EXCLUDED.pdf_path, wiki_url = EXCLUDED.wiki_url, wiki_image_url = EXCLUDED.wiki_image_url, updated_at = EXCLUDED.updated_at;
INSERT INTO kreo_products (set_number, name, franchise, sub_line, year, piece_count, kreons_count, kreons_included, description, price_retail, product_type, image_url, image_path, pdf_url, pdf_path, wiki_url, wiki_image_url, discovered_at, updated_at) VALUES ('KR4672', 'Lord Neverember', 'dungeons-dragons', 'Kreon Warriors', 2014, NULL, 1, 'Lord Neverember', 'Allegiance: Humanity, Neverwinter, Waterdeep. Lord Neverember is a Kreon Warrior representing Dagult Neverember, the Open Lord of the port of Waterdeep as well as Lord Protector of the fortified city of Neverwinter in the fantasy world of the Forgotten Realms campaign setting for Dungeons and Dragons. Included with: [[Kreon Warriors (D&D)]] Lord
Neverember (A7712000)', NULL, 'kreon', NULL, 'kreons/kr4672.jpg', NULL, NULL, 'https://kreo.fandom.com/wiki/Lord%20Neverember', 'https://static.wikia.nocookie.net/kreo/images/5/58/Neverember02.jpg/revision/latest/scale-to-width-down/800?cb=20140105202451', '2026-03-01 07:54:44.28478'::timestamp, '2026-03-01 07:54:44.28478'::timestamp) ON CONFLICT (set_number) DO UPDATE SET name = EXCLUDED.name, franchise = EXCLUDED.franchise, sub_line = EXCLUDED.sub_line, year = EXCLUDED.year, piece_count = EXCLUDED.piece_count, kreons_count = EXCLUDED.kreons_count, kreons_included = EXCLUDED.kreons_included, description = EXCLUDED.description, price_retail = EXCLUDED.price_retail, product_type = EXCLUDED.product_type, image_url = EXCLUDED.image_url, image_path = EXCLUDED.image_path, pdf_url = EXCLUDED.pdf_url, pdf_path = EXCLUDED.pdf_path, wiki_url = EXCLUDED.wiki_url, wiki_image_url = EXCLUDED.wiki_image_url, updated_at = EXCLUDED.updated_at;
INSERT INTO kreo_products (set_number, name, franchise, sub_line, year, piece_count, kreons_count, kreons_included, description, price_retail, product_type, image_url, image_path, pdf_url, pdf_path, wiki_url, wiki_image_url, discovered_at, updated_at) VALUES ('KR4673', 'Vansi', 'dungeons-dragons', 'Kreon Warriors', 2014, 30, 1, 'Vansi', 'Allegiance: Many-Arrows Tribe. Vansi is a Kreon Warrior representing the orc Vansi Bloodscar, leader of the Many-Arrows Tribe and a powerful warrior noted for bearing a spellscar, the result of exposure to magical pollution that causes her to be perpetually bathed in magic blue flames that do her no harm. As a boss character in the Cloak Tower dungeon in the Dungeons & Dragons Neverwinter online game (based in the fantasy world of the Forgotten Realms campaign setting), she provides a dangerous opponent for heroic adventurers. Included with: [[Kreon Warriors (D&D)]] 
Vansi (A7713)', 3.99, 'kreon', NULL, 'kreons/kr4673.jpg', NULL, NULL, 'https://kreo.fandom.com/wiki/Vansi', 'https://static.wikia.nocookie.net/kreo/images/f/f6/Vansi02.jpg/revision/latest/scale-to-width-down/800?cb=20140105202049', '2026-03-01 07:54:46.717818'::timestamp, '2026-03-01 09:25:32.855554'::timestamp) ON CONFLICT (set_number) DO UPDATE SET name = EXCLUDED.name, franchise = EXCLUDED.franchise, sub_line = EXCLUDED.sub_line, year = EXCLUDED.year, piece_count = EXCLUDED.piece_count, kreons_count = EXCLUDED.kreons_count, kreons_included = EXCLUDED.kreons_included, description = EXCLUDED.description, price_retail = EXCLUDED.price_retail, product_type = EXCLUDED.product_type, image_url = EXCLUDED.image_url, image_path = EXCLUDED.image_path, pdf_url = EXCLUDED.pdf_url, pdf_path = EXCLUDED.pdf_path, wiki_url = EXCLUDED.wiki_url, wiki_image_url = EXCLUDED.wiki_image_url, updated_at = EXCLUDED.updated_at;
INSERT INTO kreo_products (set_number, name, franchise, sub_line, year, piece_count, kreons_count, kreons_included, description, price_retail, product_type, image_url, image_path, pdf_url, pdf_path, wiki_url, wiki_image_url, discovered_at, updated_at) VALUES ('KR4676', 'Eye of Gruumsh', 'dungeons-dragons', 'Kreon Warriors', 2014, 32, 1, 'Eye of Gruumsh', 'Allegiance: Orc Hordes. The Eye of Gruumsh is a Kre-O Dungeons & Dragons Kreon Warrior representing devotees of the one-eyed evil orcish god Gruumsh. In particular, it seems to represent the elite Eyes of Gruumsh in the Neverwinter online game, due to being armed with a spear (rather than the typical double-axe of Eyes of Gruumsh in the tabletop Dungeons & Dragons game) and having an association with Vansi, who commanded a number of Eyes among the Many-Arrows tribe of orcs. An Eye of Gruumsh shows their devotion to their god by ritually blinding their right eye; anything that heals their vision cancels their magical powers.Eye of Gruumsh prestige class at Orcs.ca This set includes an enormous pet spider, as well as a treasure chest lined with teeth in a possible reference to the shapeshifting Mimic monsters known to disguise themselves as treasure chests and other furnishings. Included with: [[Kreon Warriors (D&D)]] Eye 
of Gruumsh (A7714000)', 3.99, 'kreon', NULL, 'kreons/kr4676.jpg', NULL, NULL, 'https://kreo.fandom.com/wiki/Eye%20of%20Gruumsh', 'https://static.wikia.nocookie.net/kreo/images/6/6a/Eyeofgruumsh02.jpg/revision/latest/scale-to-width-down/800?cb=20140105221543', '2026-03-01 07:54:49.188111'::timestamp, '2026-03-01 09:25:27.114823'::timestamp) ON CONFLICT (set_number) DO UPDATE SET name = EXCLUDED.name, franchise = EXCLUDED.franchise, sub_line = EXCLUDED.sub_line, year = EXCLUDED.year, piece_count = EXCLUDED.piece_count, kreons_count = EXCLUDED.kreons_count, kreons_included = EXCLUDED.kreons_included, description = EXCLUDED.description, price_retail = EXCLUDED.price_retail, product_type = EXCLUDED.product_type, image_url = EXCLUDED.image_url, image_path = EXCLUDED.image_path, pdf_url = EXCLUDED.pdf_url, pdf_path = EXCLUDED.pdf_path, wiki_url = EXCLUDED.wiki_url, wiki_image_url = EXCLUDED.wiki_image_url, updated_at = EXCLUDED.updated_at;
INSERT INTO kreo_products (set_number, name, franchise, sub_line, year, piece_count, kreons_count, kreons_included, description, price_retail, product_type, image_url, image_path, pdf_url, pdf_path, wiki_url, wiki_image_url, discovered_at, updated_at) VALUES ('KR4680', 'Energon Bumblebee', 'transformers', 'Micro-Changers', 2012, NULL, 1, 'Energon Bumblebee', 'Allegiance: Autobot. A Bumblebee Kreon molded entirely in clear blue plastic exclusive to New York Comic Con 2012. Energon Bumblebee comes packaged inside a small window box with an outer sleeve.', NULL, 'kreon', NULL, 'kreons/kr4680.jpg', NULL, NULL, 'https://kreo.fandom.com/wiki/Energon%20Bumblebee%20(A1556)', 'https://static.wikia.nocookie.net/kreo/images/5/54/Transformers-Kreon-Energon-Bumblebee-Possible-NYCC-Exclusive-Images-1_scaled_600.jpg/revision/latest?cb=20130218224326', '2026-03-01 07:54:50.933725'::timestamp, '2026-03-01 09:35:22.72954'::timestamp) ON CONFLICT (set_number) DO UPDATE SET name = EXCLUDED.name, franchise = EXCLUDED.franchise, sub_line = EXCLUDED.sub_line, year = EXCLUDED.year, piece_count = EXCLUDED.piece_count, kreons_count = EXCLUDED.kreons_count, kreons_included = EXCLUDED.kreons_included, description = EXCLUDED.description, price_retail = EXCLUDED.price_retail, product_type = EXCLUDED.product_type, image_url = EXCLUDED.image_url, image_path = EXCLUDED.image_path, pdf_url = EXCLUDED.pdf_url, pdf_path = EXCLUDED.pdf_path, wiki_url = EXCLUDED.wiki_url, wiki_image_url = EXCLUDED.wiki_image_url, updated_at = EXCLUDED.updated_at;
INSERT INTO kreo_products (set_number, name, franchise, sub_line, year, piece_count, kreons_count, kreons_included, description, price_retail, product_type, image_url, image_path, pdf_url, pdf_path, wiki_url, wiki_image_url, discovered_at, updated_at) VALUES ('KR4840', 'Bulldog', 'transformers', 'G.I. Joe', 2012, NULL, 1, 'Bulldog', 'Allegiance: Autobots. The Bulldog is an Autobot''s best friend! A two-piece canine minifigure included in the Stealth Bumblebee construction set, the Bulldog would later become more notable for its appearances in the Transformers Webcomic. Included with: [[Stealth Bumblebee]]', NULL, 'kreon', NULL, 'kreons/kr4840.png', NULL, NULL, 'https://kreo.fandom.com/wiki/Bulldog', 'https://static.wikia.nocookie.net/kreo/images/0/0d/Bbbulldog.png/revision/latest?cb=20140107194458', '2026-03-01 07:54:53.330494'::timestamp, '2026-03-01 07:54:53.330494'::timestamp) ON CONFLICT (set_number) DO UPDATE SET name = EXCLUDED.name, franchise = EXCLUDED.franchise, sub_line = EXCLUDED.sub_line, year = EXCLUDED.year, piece_count = EXCLUDED.piece_count, kreons_count = EXCLUDED.kreons_count, kreons_included = EXCLUDED.kreons_included, description = EXCLUDED.description, price_retail = EXCLUDED.price_retail, product_type = EXCLUDED.product_type, image_url = EXCLUDED.image_url, image_path = EXCLUDED.image_path, pdf_url = EXCLUDED.pdf_url, pdf_path = EXCLUDED.pdf_path, wiki_url = EXCLUDED.wiki_url, wiki_image_url = EXCLUDED.wiki_image_url, updated_at = EXCLUDED.updated_at;
INSERT INTO kreo_products (set_number, name, franchise, sub_line, year, piece_count, kreons_count, kreons_included, description, price_retail, product_type, image_url, image_path, pdf_url, pdf_path, wiki_url, wiki_image_url, discovered_at, updated_at) VALUES ('KR5069', 'Captain Kirk', 'star-trek', 'Into Darkness', 2013, NULL, 1, 'Captain Kirk', 'Allegiance: Starfleet. Captain James Tiberius Kirk is a major character in the Star Trek franchise, both within Kre-O and beyond. Represented by no less than five kreon minifigures, he is featured prominently in promotional material. In general, he is presented in his role as captain of the U.S.S. Enterprise, a vessel serving under the Starfleet Command of the United Federation of Planets; the majority of kreons represent him in the alternate timeline of the rebooted film continuity beginning with the 2009 premiere of the film Star Trek. As a Kreon, Kirk is recognizable by his caucasian skin, light brown hair, and tendency to be represented with a bemused expression. As a member of the Command division in Starfleet, Kirk usually wears a yellow or gold-toned uniform (this only reflects the style of the stories set in the late 22nd Century; Star Trek media set after that uses red uniforms for command and gold uniforms for security personnel).

The "standard" Kirk kreon is the one included in the U.S.S. Enterpr Included with: [[U.S.S. Enterprise (A3137)]]', NULL, 'kreon', NULL, 'kreons/kr5069.jpg', NULL, NULL, 'https://kreo.fandom.com/wiki/Captain%20Kirk', 'https://static.wikia.nocookie.net/kreo/images/8/8a/Brandnav_kirk.jpg/revision/latest?cb=20140116034249', '2026-03-01 07:54:55.287545'::timestamp, '2026-03-01 07:54:55.287545'::timestamp) ON CONFLICT (set_number) DO UPDATE SET name = EXCLUDED.name, franchise = EXCLUDED.franchise, sub_line = EXCLUDED.sub_line, year = EXCLUDED.year, piece_count = EXCLUDED.piece_count, kreons_count = EXCLUDED.kreons_count, kreons_included = EXCLUDED.kreons_included, description = EXCLUDED.description, price_retail = EXCLUDED.price_retail, product_type = EXCLUDED.product_type, image_url = EXCLUDED.image_url, image_path = EXCLUDED.image_path, pdf_url = EXCLUDED.pdf_url, pdf_path = EXCLUDED.pdf_path, wiki_url = EXCLUDED.wiki_url, wiki_image_url = EXCLUDED.wiki_image_url, updated_at = EXCLUDED.updated_at;
INSERT INTO kreo_products (set_number, name, franchise, sub_line, year, piece_count, kreons_count, kreons_included, description, price_retail, product_type, image_url, image_path, pdf_url, pdf_path, wiki_url, wiki_image_url, discovered_at, updated_at) VALUES ('KR5081', 'Scotty', 'star-trek', 'Into Darkness', 2013, NULL, 1, 'Scotty', 'Allegiance: Starfleet. Montgomery "Scotty" Scott is a character in the Star Trek franchise, represented in the Kre-O Star Trek sub-line by at least two individual Kreon minifigures. He is mostly represented in his role as a Chief Engineer of the U.S.S. Enterprise (though no Enterprise set is yet available that includes him) with the rank of Lieutenant Commander, with both existing kreons representing him as he appears in the alternate timeline of the rebooted film continuity beginning with the 2009 premiere of the film Star Trek. As an engineer, Scotty is noted for his association not only with the upkeep of the Enterprise, but his in-depth knowledge of its transporter systems that are used to teleport matter (including living creatures) from the ship to nearby locations.

As a Kreon, he is recognizable by his Caucasian skin and light-brown hair in a swept-back mold that seems to be an imitation of the receding hairline of the actor Simon Pegg, who portrays him in the rebooted films. As a member of Starfleet Included with: [[Transporter Trouble]]', NULL, 'kreon', NULL, 'kreons/kr5081.jpg', NULL, NULL, 'https://kreo.fandom.com/wiki/Scotty', 'https://static.wikia.nocookie.net/kreo/images/9/97/Kre-o-star-trek-scotty-minifigure-589-p.jpg/revision/latest?cb=20140116233607', '2026-03-01 07:54:57.204102'::timestamp, '2026-03-01 07:54:57.204102'::timestamp) ON CONFLICT (set_number) DO UPDATE SET name = EXCLUDED.name, franchise = EXCLUDED.franchise, sub_line = EXCLUDED.sub_line, year = EXCLUDED.year, piece_count = EXCLUDED.piece_count, kreons_count = EXCLUDED.kreons_count, kreons_included = EXCLUDED.kreons_included, description = EXCLUDED.description, price_retail = EXCLUDED.price_retail, product_type = EXCLUDED.product_type, image_url = EXCLUDED.image_url, image_path = EXCLUDED.image_path, pdf_url = EXCLUDED.pdf_url, pdf_path = EXCLUDED.pdf_path, wiki_url = EXCLUDED.wiki_url, wiki_image_url = EXCLUDED.wiki_image_url, updated_at = EXCLUDED.updated_at;
