Pack Collection 2 (A4534)', NULL, 'kreon', NULL, 'kreons/kr31831.JPG', NULL, 'pdfs/anthony-flash-gambello_instructions_scan.pdf', 'https://kreo.fandom.com/wiki/Anthony%20%22Flash%22%20Gambello', 'https://static.wikia.nocookie.net/kreo/images/9/92/Flash.JPG/revision/latest?cb=20140118191351', '2026-03-01 07:54:59.462127'::timestamp, '2026-03-01 10:31:42.629239'::timestamp) ON CONFLICT (set_number) DO UPDATE SET name = EXCLUDED.name, franchise = EXCLUDED.franchise, sub_line = EXCLUDED.sub_line, year = EXCLUDED.year, piece_count = EXCLUDED.piece_count, kreons_count = EXCLUDED.kreons_count, kreons_included = EXCLUDED.kreons_included, description = EXCLUDED.description, price_retail = EXCLUDED.price_retail, product_type = EXCLUDED.product_type, image_url = EXCLUDED.image_url, image_path = EXCLUDED.image_path, pdf_url = EXCLUDED.pdf_url, pdf_path = EXCLUDED.pdf_path, wiki_url = EXCLUDED.wiki_url, wiki_image_url = EXCLUDED.wiki_image_url, updated_at = EXCLUDED.updated_at;
