INSERT INTO kreo_products (set_number, name, franchise, sub_line, year, piece_count, kreons_count, kreons_included, description, price_retail, product_type, image_url, image_path, pdf_url, pdf_path, wiki_url, wiki_image_url, discovered_at, updated_at) VALUES ('38975', 'Air Assault', 'battleship', 'Movie', 2012, 36, NULL, NULL, 'thumbPretend to take your mission to the sky! Build 2 fighter planes with the BATTLESHIP AIR ASSAULT Set and pit them against each other in an aerial battle between your Pilot and Alien KREON figures! Build your own firing weapons and put your KREON figures in the cockpits. With firing missiles, these awesome aircraft will "take to the air" for the fiercest dogfight ever!Build 2 fighter planes! Build your own firing weapons! Opening cockpit fit', 3.99, 'building_set', NULL, 'battleship/38975.jpg', NULL, 'pdfs/38975_instructions_scan.pdf', 'https://kreo.fandom.com/wiki/Air%20Assault%20(38975)', 'https://static.wikia.nocookie.net/kreo/images/5/52/6D424DDB5056900B10A5E8A59987F1E4.jpg/revision/latest?cb=20130315024749', '2026-03-01 08:05:46.633889'::timestamp, '2026-03-01 10:29:17.620209'::timestamp) ON CONFLICT (set_number) DO UPDATE SET name = EXCLUDED.name, franchise = EXCLUDED.franchise, sub_line = EXCLUDED.sub_line, year = EXCLUDED.year, piece_count = EXCLUDED.piece_count, kreons_count = EXCLUDED.kreons_count, kreons_included = EXCLUDED.kreons_included, description = EXCLUDED.description, price_retail = EXCLUDED.price_retail, product_type = EXCLUDED.product_type, image_url = EXCLUDED.image_url, image_path = EXCLUDED.image_path, pdf_url = EXCLUDED.pdf_url, pdf_path = EXCLUDED.pdf_path, wiki_url = EXCLUDED.wiki_url, wiki_image_url = EXCLUDED.wiki_image_url, updated_at = EXCLUDED.updated_at;
INSERT INTO kreo_products (set_number, name, franchise, sub_line, year, piece_count, kreons_count, kreons_included, description, price_retail, product_type, image_url, image_path, pdf_url, pdf_path, wiki_url, wiki_image_url, discovered_at, updated_at) VALUES ('WK2658', 'Alien Strike', 'battleship', 'Movie', 2012, NULL, NULL, NULL, 'thumbWith 277 bricks and other construction pieces, you can build your own battle against alien invasion! Build an alien ship and firing weapons for your KREON figures! Your Alien Pilot and Alien Gunner figures can crew the alien ship while your Raikes and Hopper figures ride their skiff into battle against them! Look inside the package for weapon building ideas. Build and rebuild their weapons for exciting blasting action in the sky, on the ground o', 29.99, 'building_set', NULL, 'battleship/wk2658.jpg', NULL, NULL, 'https://kreo.fandom.com/wiki/Alien%20Strike%20(Kre-O)', 'https://static.wikia.nocookie.net/kreo/images/b/b9/308E8EFF5056900B10B240F6F95D766B.jpg/revision/latest?cb=20130315030523', '2026-03-01 08:05:48.822283'::timestamp, '2026-03-01 09:36:11.812847'::timestamp) ON CONFLICT (set_number) DO UPDATE SET name = EXCLUDED.name, franchise = EXCLUDED.franchise, sub_line = EXCLUDED.sub_line, year = EXCLUDED.year, piece_count = EXCLUDED.piece_count, kreons_count = EXCLUDED.kreons_count, kreons_included = EXCLUDED.kreons_included, description = EXCLUDED.description, price_retail = EXCLUDED.price_retail, product_type = EXCLUDED.product_type, image_url = EXCLUDED.image_url, image_path = EXCLUDED.image_path, pdf_url = EXCLUDED.pdf_url, pdf_path = EXCLUDED.pdf_path, wiki_url = EXCLUDED.wiki_url, wiki_image_url = EXCLUDED.wiki_image_url, updated_at = EXCLUDED.updated_at;
