INSERT INTO kreo_products (set_number, name, franchise, sub_line, year, piece_count, kreons_count, kreons_included, description, price_retail, product_type, image_url, image_path, pdf_url, pdf_path, wiki_url, wiki_image_url, discovered_at, updated_at) VALUES ('WK2687', 'U.S.S. Missouri', 'battleship', 'Movie', 2012, NULL, NULL, NULL, 'thumbIn your imaginary battles, the aliens are powerful and well-armed, but luckily, you’ve got the incredible armaments of the U.S.S. MISSOURI at your command. Missiles, torpedoes, machine guns and the most highly trained KREON figure commandos are ready to take on the otherworldly threat in this flagship building set from KRE-O! Build it and join the battle!If you want to be on the cutting edge of brick play, and imagine yourself on the front lines of a battle to protect the Earth, KRE-O BATTLESHIP Building Sets are for you. High-octane, in your face action building is yours, with the sets that let you build like you play – without limits!Build the mighty U.S.S. MISSOURI! 6 customizable missile launchers with firing missiles! 3 interior levels – including central control room, captain’s navigation tower, and soldier sleeping barracks with alien examination room. Working crane lifts the attack boat! Works with leading construction brands!Includes 545-piece construction kit to build th', 69.99, 'building_set', NULL, 'battleship/wk2687.jpg', NULL, NULL, 'https://kreo.fandom.com/wiki/U.S.S.%20Missouri%20(Kre-O)', 'https://static.wikia.nocookie.net/kreo/images/b/ba/308ED82D5056900B10ED949B0BD56FFE.jpg/revision/latest?cb=20130315032611', '2026-03-01 08:06:07.187886'::timestamp, '2026-03-01 09:36:11.812847'::timestamp) ON CONFLICT (set_number) DO UPDATE SET name = EXCLUDED.name, franchise = EXCLUDED.franchise, sub_line = EXCLUDED.sub_line, year = EXCLUDED.year, piece_count = EXCLUDED.piece_count, kreons_count = EXCLUDED.kreons_count, kreons_included = EXCLUDED.kreons_included, description = EXCLUDED.description, price_retail = EXCLUDED.price_retail, product_type = EXCLUDED.product_type, image_url = EXCLUDED.image_url, image_path = EXCLUDED.image_path, pdf_url = EXCLUDED.pdf_url, pdf_path = EXCLUDED.pdf_path, wiki_url = EXCLUDED.wiki_url, wiki_image_url = EXCLUDED.wiki_image_url, updated_at = EXCLUDED.updated_at;
