<gallery widths="100" c', 29.99, 'building_set', NULL, 'transformers/wk2532.jpg', NULL, 'pdfs/WK2532_instructions_scan.pdf', 'https://kreo.fandom.com/wiki/Street%20Showdown%20(Kre-O)', 'https://static.wikia.nocookie.net/kreo/images/d/d4/Wheeljack-Car_1339101179.jpg/revision/latest?cb=20130309061651', '2026-03-01 08:12:19.344775'::timestamp, '2026-03-01 10:31:23.74257'::timestamp) ON CONFLICT (set_number) DO UPDATE SET name = EXCLUDED.name, franchise = EXCLUDED.franchise, sub_line = EXCLUDED.sub_line, year = EXCLUDED.year, piece_count = EXCLUDED.piece_count, kreons_count = EXCLUDED.kreons_count, kreons_included = EXCLUDED.kreons_included, description = EXCLUDED.description, price_retail = EXCLUDED.price_retail, product_type = EXCLUDED.product_type, image_url = EXCLUDED.image_url, image_path = EXCLUDED.image_path, pdf_url = EXCLUDED.pdf_url, pdf_path = EXCLUDED.pdf_path, wiki_url = EXCLUDED.wiki_url, wiki_image_url = EXCLUDED.wiki_image_url, updated_at = EXCLUDED.updated_at;
